# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from flask_graphql import GraphQLView
from graphene import ObjectType, String, List, Float, Schema, Field

app = Flask(__name__)

class Review(ObjectType):
    user = String()
    rating = Float()
    comment = String()

class Product(ObjectType):
    id = String()
    name = String()
    description = String()
    price = Float()
    reviews = List(Review)

class Category(ObjectType):
    id = String()
    name = String()
    products = List(Product)

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)

    def resolve_products(self, info):
        return [
            Product(id="1", name="Product A", description="Description A", price=29.99, 
                    reviews=[Review(user="User1", rating=4.5, comment="Great product!")]),
            Product(id="2", name="Product B", description="Description B", price=19.99, 
                    reviews=[Review(user="User2", rating=5.0, comment="Excellent!"),
                             Review(user="User3", rating=4.0, comment="Very good!")]),
        ]

    def resolve_categories(self, info):
        return [
            Category(id="1", name="Category A", products=[
                Product(id="1", name="Product A", description="Description A", price=29.99),
                Product(id="2", name="Product B", description="Description B", price=19.99)
            ]),
            Category(id="2", name="Category B", products=[
                Product(id="3", name="Product C", description="Description C", price=39.99)
            ])
        ]

schema = Schema(query=Query)

app.add_url_rule('/graphql', view_func=GraphQLView.as_view('graphql', 
    schema=schema, 
    graphiql=True  # Enable the GraphiQL interface for introspection
))

if __name__ == '__main__':
    app.run(debug=True)